// ---- helpers ----------------------------------------------------------

func assetCardID(id int64) string {
	return fmt.Sprintf("asset-%d", id)
}

func assetCardClass(a assets.Asset, usage map[int64]int) string {
	if usage != nil {
		if n, ok := usage[a.ID]; ok && n == 0 {
			return "bx-asset-card bx-asset-card--orphan"
		}
	}
	return "bx-asset-card"
}

func assetCardTitle(a assets.Asset, usage map[int64]int) string {
	if usage == nil {
		return a.Name
	}
	if n, ok := usage[a.ID]; ok {
		return fmt.Sprintf("%s — used by %d entit%s", a.Name, n, plural(n, "y", "ies"))
	}
	return a.Name
}

func assetURL(a assets.Asset, publicURL func(string) string) string {
	if publicURL == nil {
		return ""
	}
	return publicURL(a.ContentAddressedPath)
}

func countByKind(items []assets.Asset, kind string) int {
	n := 0
	for _, a := range items {
		if string(a.Kind) == kind {
			n++
		}
	}
	return n
}

func firstNTags(tags []string, n int) []string {
	if len(tags) <= n {
		return tags
	}
	return tags[:n]
}

func plural(n int, one, many string) string {
	if n == 1 {
		return one
	}
	return many
}

